var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"현재, 그로니아 파레마\\n반군 점령지역","JPN":"現在、グロニア パレマ\\n反軍占領地域","ENG":"[[","TWN":"現在，格羅尼亞 波雷馬\\n叛軍佔領地區","THA":"ปัจจุบัน โกรเนีย พาเรมา\\nดินแดนในครอบครองของฝ่ายกบฏ","VTN":"Hiện tại, Gronia Parema\\nLãnh thổ của phiến quân","SCN":"当前，格洛尼亚的巴乐马\\n叛军占领区","DEU":"[[","FRA":"Présent\\nParema, Gronia\\nBase d'opérations des rebelles"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>주민들에게 알린다. 30분 후 식량 배급을 실시할 예정이다.</color>","JPN":"<color=#ffd34c>住民に告げる。30分後食料の配給を行う予定だ。</color>","ENG":"<color=#ffd34c>Notice to residents. Food distribution will take place in half an hour.</color>","TWN":"<color=#ffd34c>居民注意，30分鐘後將發放糧食。</color>"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>배급 장소로 올 때는 반드시 통행증을 지참할 것. 반복한다…….</color>","JPN":"<color=#ffd34c>配給所に来るときは必ず通行証を持ってくるように。繰り返す……</color>","ENG":"<color=#ffd34c>Bring your pass when you come to the distribution center. I repeat...</color>","TWN":"<color=#ffd34c>移動至配給地點時務必攜帶通行證。再重複一次……</color>"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"제길, 우리 먹고 뒈질 것도 없는 마당에 이게 무슨 짓이야.","JPN":"ちくしょう、俺たちの分もないのに何をやってるんだ。","ENG":"Damn it, there's not that much food left for us. Why the hell are they giving this much out?","TWN":"可惡！我們自己吃都不夠了，這是在幹嘛！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"하여튼 우리 대장님은 사람이 너무 물러서 문제야.","JPN":"まったく、俺らの隊長は甘すぎるんだよ。","ENG":"Our captain is too soft. It's a problem.","TWN":"我們隊長的問題就是心太軟！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"그게 좋은 거지. 강경파 놈들처럼 욕 먹을 필요 없잖아.","JPN":"それがいいんだろう。強硬派の連中みたいに悪口言われずに済むじゃないか。","ENG":"Come on man, it's a good thing. No need to get a mouthful like those bastards from the hardliners.","TWN":"這是好事吧？要是隊長跟強硬派的一樣，那我們的日子會很難過吧？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"이거로 주둥이나 막고 있어. 운전 방해하지 말고.","JPN":"これ飲んで黙ってろ。運転の邪魔すんじゃねぇ。","ENG":"Here, drink some of this and don't distract me while I'm driving.","TWN":"拿這個把你的嘴堵起來！別妨礙我開車！"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"오, 술이잖아? 어디서 이런 귀한 걸 구했대?","JPN":"お、酒じゃねぇか？　こんな貴重なものをどこで手に入れたんだ？","ENG":"Oh, whiskey? How did you acquire something so valuable?","TWN":"嗯？這是酒？這麼珍貴的東西，你是從哪弄來的？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"조카가 보급계거든. 후방의 윗분들은 술이고 여자고 넘치니까 한 병 정도 슬쩍해도 몰라.","JPN":"甥っ子が補給係でさ。後方のお偉方は酒も女も持て余してるから、一本ぐらいこっそり盗んでもわかりゃしねぇのさ。","ENG":"My nephew has connections with the supply chain. The higher ups in the back have so much whiskey and women, no one notices if you take one bottle.","TWN":"我的姪子是配給部的，後勤的那些長官最不缺的就是酒和女人，偷走一瓶他們不會發現啦～"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"쳇…. 고생은 우리가 다 하는데 윗분들은 뒷구멍으로 다 꿍쳐 놓네.","JPN":"ちぇっ……苦労は俺たちにさせて、おいしいとこは全部お偉方が持っていくんだな。","ENG":"Tchh... We are working so hard while the higher ups just mess around in the back.","TWN":"嘖…我們在前方衝鋒陷陣，那些高官卻在後方喝酒玩女人？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"흐흐, 그러게나 말이야. 기회 봐서 정부군에 투항이나 할까?","JPN":"へへ、そうだな。機を見て政府軍に投降でもするか？","ENG":"Heh, that's what I'm saying, man. You want to take this opportunity and surrender to the government forces?","TWN":"呵呵，說的沒錯！我看有機會的話，乾脆向政府軍投誠吧？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"보안국 놈들이 가만두겠냐? 분명 아는 거 다 불라고 쥐어짠 다음……","JPN":"保安局の連中が放っとくわけねぇだろ？　絶対知ってること全部吐けって……","ENG":"You think the National Security wouldn't catch us? Bro, if they caught us we’d be—","TWN":"安全局的傢伙會放過我們嗎？一定會對我們嚴刑拷問，然後……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"젠장, 아까운 술 다 쏟았네!","JPN":"おい、酒零したじゃねぇか！","ENG":"Damn it, I spilled the whiskey!","TWN":"該死！這麼珍貴的酒都打翻了啦！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"갑자기 브레이크는 왜 밟아? 술 냄새 맡고 취했냐?","JPN":"なにいきなりブレーキ踏んでんだ？　酒の匂いで酔ったか？","ENG":"Why the hell did you have to slam on the brakes all of a sudden? Are you drunk just from smelling it?","TWN":"幹嘛突然緊急剎車？你是聞到酒的味道也會醉是不是？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"정신 차리고 총이나 챙겨, 등신아. 저 앞에 여자 안 보이냐?","JPN":"ふざけないで銃を持て、タコ。あそこに女がいるだろ？","ENG":"Pull yourself together and ready your gun, idiot. Can't you see the girl in front of us?","TWN":"少在那邊嘴砲，把槍拿好！你沒看到前面有個女的嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"뭐? 여자?","JPN":"はあ？　女？","ENG":"What? A girl?","TWN":"什麼女的？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};